const LITE_ROLE_EXPANSION: Record<string, ModelRole[]> = {
  chat: ["chat", "fallback-chat"],
  code: ["code", "fallback-code", "grimoire", "agent-planner", "code-review"],
  reason: ["reason", "agent"],
  classify: ["classify"],
  vision: ["vision", "vision-ocr"],
};

function resolveStateDir(baseDir?: string): string {
  const stateDir = process.env["SQUIDLEY_STATE_DIR"]?.trim();
  if (stateDir) return resolve(stateDir);
  const base = baseDir ?? process.env["SQUIDLEY_BASE_DIR"] ?? process.cwd();
  return resolve(base, "state");
}

function readLiteDefaults(baseDir?: string): LiteDefaults {
  try {
    const base = baseDir ?? process.env["SQUIDLEY_BASE_DIR"] ?? process.cwd();
    const raw = readFileSync(join(base, "config", "lite-defaults.json"), "utf-8");
    return JSON.parse(raw) as LiteDefaults;
  } catch {
    return {
      defaults: {
        chat: { model: "qwen3.5:4b", provider: "ollama" },
        code: { model: "qwen3.5:9b", provider: "ollama" },
        classify: { model: "qwen3.5:4b", provider: "ollama" },
        reason: { model: "qwen3.5:9b", provider: "ollama" },
        vision: null,
      },
      liteMode: true,
      cloudEnabled: false,
    };
  }
}

function providerServiceId(provider: string): string {
  return PROVIDER_SERVICE_IDS[provider] ?? provider;
}

function tierForProvider(provider: string): 0 | 1 | 2 | 3 {
  if (provider.includes("provider-ollama") || provider.includes("provider-llamacpp")) return 0;
  if (provider.includes("provider-groq") || provider.includes("provider-google-ai-studio") || provider.includes("provider-cerebras") || provider.includes("provider-openrouter-free")) return 1;
  if (provider.includes("provider-openrouter") || provider.includes("provider-modelstudio") || provider.includes("provider-zai")) return 2;
  return 3;
}

function displayNameForModel(model: string): string {
  const qwenMatch = model.match(/^qwen3\.5:(\d+)b$/i);
  if (qwenMatch) return "Qwen 3.5 " + qwenMatch[1] + "B";
  if (model === "arcee-ai/trinity-large-thinking") return "Arcee Trinity Large Thinking";
  return model;
}

function expandLiteRoles(defaults: LiteDefaults["defaults"]): Partial<Record<ModelRole, string>> {
  const roles: Partial<Record<ModelRole, string>> = {};
  for (const [key, value] of Object.entries(defaults)) {
    if (!value) continue;
    const expanded = LITE_ROLE_EXPANSION[key] ?? [];
    for (const role of expanded) roles[role] = value.model;
  }
  return roles;
}

function uuid(): string {
  return randomUUID();
}

function rowToEntry(row: ModelRow, roles: ModelRole[]): ModelEntry {
  return {
    id: row.id,
    name: row.name,
    model: row.model,
    provider: row.provider,
    tier: row.tier ?? tierForProvider(row.provider),
    roles,
    max_tokens: row.max_tokens,
    active: row.active === 1,
    notes: row.notes,
    cost_per_m_input: row.cost_per_m_input ?? null,
    cost_per_m_output: row.cost_per_m_output ?? null,
    thinking_mode: (row.thinking_mode as "default" | "enabled" | "disabled") ?? "default",
    created_at: row.created_at,
  };
}

export class ModelRegistry {
  private db: InstanceType<typeof Database>;
  private dbPath: string;
  private bootstrapSource: "database" | "lite-defaults" = "database";
  private healthHint: string | null = null;
  private cloudEnabled = true;

  constructor(baseDir: string) {
    const stateDir = resolveStateDir(baseDir);
    mkdirSync(stateDir, { recursive: true });
    this.dbPath = join(stateDir, "nous-registry.db");
    const liteDefaults = readLiteDefaults(baseDir);
    this.cloudEnabled = liteDefaults.cloudEnabled;

    try {
      this.db = new Database(this.dbPath);
      this.db.pragma("journal_mode = WAL");
      this.initializeSchema();
      this.ensureSeeded(liteDefaults);
      this.ensureTierCatalog();
      this.ensureRoleplayModel();
      this.ensureTrinityModel();
    } catch (err) {
      console.error("[nous] registry corrupt, falling back to lite defaults:", err);
      this.db = new Database(":memory:");
      this.bootstrapSource = "lite-defaults";
      this.healthHint = "Registry corrupt — loaded lite-defaults.json in recovery mode.";
      this.initializeSchema();
      this.seedLiteDefaults(liteDefaults);
      this.ensureTierCatalog();
      this.ensureRoleplayModel();
      this.ensureTrinityModel();
    }
  }

  private initializeSchema(): void {
    this.db.exec(`
      CREATE TABLE IF NOT EXISTS models (
        id               TEXT PRIMARY KEY,
        name             TEXT NOT NULL,
        model            TEXT NOT NULL,
        provider         TEXT NOT NULL,
        tier             INTEGER NOT NULL DEFAULT 2,
        role             TEXT,
        max_tokens       INTEGER,
        active           INTEGER NOT NULL DEFAULT 1,
        notes            TEXT,
        cost_per_m_input REAL,
        cost_per_m_output REAL,
        thinking_mode    TEXT DEFAULT 'default',
        created_at       TEXT NOT NULL
      );
    `);

    this.db.exec(`
      CREATE TABLE IF NOT EXISTS role_assignments (
        role     TEXT PRIMARY KEY,
        model_id TEXT NOT NULL
      );
    `);

    try { this.db.exec("ALTER TABLE models ADD COLUMN cost_per_m_input REAL"); } catch {}
    try { this.db.exec("ALTER TABLE models ADD COLUMN cost_per_m_output REAL"); } catch {}
    try { this.db.exec("ALTER TABLE models ADD COLUMN thinking_mode TEXT DEFAULT 'default'"); } catch {}
    try { this.db.exec("ALTER TABLE models ADD COLUMN tier INTEGER NOT NULL DEFAULT 2"); } catch {}

    const assignCount = (this.db.prepare("SELECT COUNT(*) as n FROM role_assignments").get() as { n: number }).n;
    if (assignCount === 0) {
      this.db.exec(`
        INSERT OR IGNORE INTO role_assignments (role, model_id)
        SELECT role, id FROM models WHERE role IS NOT NULL AND role != ''
      `);
    }
  }

  private ensureRoleplayModel(): void {
    const existing = this.db.prepare("SELECT id FROM models WHERE model = ? AND provider = ?")
      .get("MiniMax-M2.7-her", "squidley.integration.provider-minimax") as { id: string } | undefined;
    let modelId: string;
    if (existing) {
      modelId = existing.id;
    } else {
      modelId = uuid();
      this.db.prepare(`
        INSERT INTO models (id, name, model, provider, tier, max_tokens, active, notes, cost_per_m_input, cost_per_m_output, thinking_mode, created_at)
        VALUES (@id, @name, @model, @provider, @tier, @max_tokens, @active, @notes, @cost_per_m_input, @cost_per_m_output, @thinking_mode, @created_at)
      `).run({
        id: modelId,
        name: "MiniMax M2.7 Her",
        model: "MiniMax-M2.7-her",
        provider: "squidley.integration.provider-minimax",
        tier: 3,
        max_tokens: null,
        active: 1,
        notes: "Roleplay-optimized — companions, personas, narrative, character work",
        cost_per_m_input: 0.30,
        cost_per_m_output: 1.20,
        thinking_mode: "default",
        created_at: new Date().toISOString(),
      });
    }
    const roleAssignment = this.db.prepare("SELECT model_id FROM role_assignments WHERE role = 'roleplay'").get() as { model_id: string } | undefined;
    if (!roleAssignment) {
      this.db.prepare("INSERT OR REPLACE INTO role_assignments (role, model_id) VALUES ('roleplay', ?)").run(modelId);
    }
  }

  private ensureTrinityModel(): void {
    const existing = this.db.prepare("SELECT id FROM models WHERE model = ? AND provider = ?")
      .get("arcee-ai/trinity-large-thinking", "squidley.integration.provider-openrouter") as { id: string } | undefined;
    if (existing) return;
    this.db.prepare(`
      INSERT INTO models (id, name, model, provider, tier, max_tokens, active, notes, cost_per_m_input, cost_per_m_output, thinking_mode, created_at)
      VALUES (@id, @name, @model, @provider, @tier, @max_tokens, @active, @notes, @cost_per_m_input, @cost_per_m_output, @thinking_mode, @created_at)
    `).run({
      id: uuid(),
      name: "Arcee Trinity Large Thinking",
      model: "arcee-ai/trinity-large-thinking",
      provider: "squidley.integration.provider-openrouter",
      tier: 2,
      max_tokens: 262144,
      active: 1,
      notes: "Arcee AI reasoning model — strong on PinchBench, agentic workloads, and reasoning tasks. 262K context.",
      cost_per_m_input: 0.22,
      cost_per_m_output: 0.85,
      thinking_mode: "default",
      created_at: new Date().toISOString(),
    });
  }

  private ensureSeeded(liteDefaults: LiteDefaults): void {
    const count = (this.db.prepare("SELECT COUNT(*) as n FROM models").get() as { n: number }).n;
    if (count > 0) return;
    this.bootstrapSource = "lite-defaults";
    this.healthHint = "Registry empty — loaded lite-defaults.json.";
    this.seedLiteDefaults(liteDefaults);
  }

  private seedLiteDefaults(liteDefaults: LiteDefaults): void {
    const expandedRoles = expandLiteRoles(liteDefaults.defaults);
    const uniqueModels = new Map<string, { name: string; model: string; provider: string }>();

    for (const value of Object.values(liteDefaults.defaults)) {
      if (!value) continue;
      const provider = providerServiceId(value.provider);
      const key = provider + "::" + value.model;
      if (!uniqueModels.has(key)) {
        uniqueModels.set(key, {
          name: displayNameForModel(value.model),
          model: value.model,
          provider,
        });
      }
    }

    const insert = this.db.prepare(`
      INSERT INTO models (id, name, model, provider, tier, max_tokens, active, notes, cost_per_m_input, cost_per_m_output, thinking_mode, created_at)
      VALUES (@id, @name, @model, @provider, @tier, @max_tokens, @active, @notes, @cost_per_m_input, @cost_per_m_output, @thinking_mode, @created_at)
    `);
    const insertRole = this.db.prepare("INSERT OR REPLACE INTO role_assignments (role, model_id) VALUES (@role, @model_id)");

    const tx = this.db.transaction(() => {
      const idsByModel = new Map<string, string>();
      for (const model of uniqueModels.values()) {
        const id = uuid();
        insert.run({
          id,
          name: model.name,
          model: model.model,
          provider: model.provider,
          tier: tierForProvider(model.provider),
          max_tokens: null,
          active: 1,
          notes: "Bootstrapped from lite-defaults.json",
          cost_per_m_input: null,
          cost_per_m_output: null,
          thinking_mode: "default",
          created_at: new Date().toISOString(),
        });
        idsByModel.set(model.model, id);
      }
      for (const [role, modelName] of Object.entries(expandedRoles) as Array<[ModelRole, string]>) {
        const modelId = idsByModel.get(modelName);
        if (modelId) insertRole.run({ role, model_id: modelId });
      }
    });

    tx();
  }

  private ensureTierCatalog(): void {
    const insert = this.db.prepare(`
      INSERT INTO models (id, name, model, provider, tier, max_tokens, active, notes, cost_per_m_input, cost_per_m_output, thinking_mode, created_at)
      VALUES (@id, @name, @model, @provider, @tier, @max_tokens, @active, @notes, @cost_per_m_input, @cost_per_m_output, @thinking_mode, @created_at)
    `);
    const tx = this.db.transaction(() => {
      for (const entry of BUILTIN_TIER_CATALOG) {
        const existing = this.db.prepare("SELECT id FROM models WHERE model = ? AND provider = ?").get(entry.model, entry.provider) as { id: string } | undefined;
        if (existing) {
          const activeClause = entry.active !== undefined ? ", active = ?" : "";
          const activeParams = entry.active !== undefined ? [entry.active ? 1 : 0] : [];
          this.db.prepare(`
            UPDATE models
            SET tier = ?,
                notes = COALESCE(notes, ?),
                max_tokens = COALESCE(max_tokens, ?),
                cost_per_m_input = COALESCE(cost_per_m_input, ?),
                cost_per_m_output = COALESCE(cost_per_m_output, ?),
                thinking_mode = COALESCE(thinking_mode, ?)${activeClause}
            WHERE id = ?
          `).run(
            entry.tier,
            entry.notes,
            entry.max_tokens ?? null,
            entry.cost_per_m_input ?? null,
            entry.cost_per_m_output ?? null,
            entry.thinking_mode ?? "default",
            ...activeParams,
            existing.id,
          );
          continue;
        }
        insert.run({
          id: uuid(),
          name: entry.name,
          model: entry.model,
          provider: entry.provider,
          tier: entry.tier,
          max_tokens: entry.max_tokens ?? null,
          active: entry.active ? 1 : 0,
          notes: entry.notes,
          cost_per_m_input: entry.cost_per_m_input ?? null,
          cost_per_m_output: entry.cost_per_m_output ?? null,
          thinking_mode: entry.thinking_mode ?? "default",
          created_at: new Date().toISOString(),
        });
      }
    });
    tx();
  }

  private buildRolesMap(): Map<string, ModelRole[]> {
    const assignments = this.db.prepare("SELECT role, model_id FROM role_assignments").all() as AssignmentRow[];
    const map = new Map<string, ModelRole[]>();
    for (const { role, model_id } of assignments) {
      const items = map.get(model_id) ?? [];
      items.push(role);
      map.set(model_id, items);
    }
    return map;
  }

  list(): ModelEntry[] {
    const rows = this.db.prepare("SELECT * FROM models ORDER BY created_at ASC").all() as ModelRow[];
    const rolesMap = this.buildRolesMap();
    return rows.map((row) => rowToEntry(row, rolesMap.get(row.id) ?? []));
  }

  get(id: string): ModelEntry | null {
    const row = this.db.prepare("SELECT * FROM models WHERE id = ?").get(id) as ModelRow | undefined;
    if (!row) return null;
    const assignments = this.db.prepare("SELECT role FROM role_assignments WHERE model_id = ?").all(id) as Array<{ role: ModelRole }>;
    return rowToEntry(row, assignments.map((item) => item.role));
  }

  add(entry: Omit<ModelEntry, "id" | "created_at" | "roles" | "tier"> & Partial<Pick<ModelEntry, "tier">>): ModelEntry {
    const existing = this.db.prepare("SELECT id FROM models WHERE model = ? AND provider = ?").get(entry.model, entry.provider) as { id: string } | undefined;
    if (existing) return this.get(existing.id)!;

    const id = uuid();
    const created_at = new Date().toISOString();
    this.db.prepare(`
      INSERT INTO models (id, name, model, provider, tier, max_tokens, active, notes, cost_per_m_input, cost_per_m_output, thinking_mode, created_at)
      VALUES (@id, @name, @model, @provider, @tier, @max_tokens, @active, @notes, @cost_per_m_input, @cost_per_m_output, @thinking_mode, @created_at)
    `).run({
      id,
      name: entry.name,
      model: entry.model,
      provider: entry.provider,
      tier: entry.tier ?? tierForProvider(entry.provider),
      max_tokens: entry.max_tokens ?? null,
      active: entry.active ? 1 : 0,
      notes: entry.notes ?? null,
      cost_per_m_input: entry.cost_per_m_input ?? null,
      cost_per_m_output: entry.cost_per_m_output ?? null,
      thinking_mode: entry.thinking_mode ?? "default",
      created_at,
    });
    return this.get(id)!;
  }

  update(id: string, patch: Partial<Omit<ModelEntry, "id" | "created_at" | "roles">>): ModelEntry | null {
    const existing = this.get(id);
    if (!existing) return null;

    const fields: string[] = [];
    const values: Record<string, unknown> = { id };

    if (patch.name !== undefined) { fields.push("name = @name"); values.name = patch.name; }
    if (patch.model !== undefined) { fields.push("model = @model"); values.model = patch.model; }
    if (patch.provider !== undefined) { fields.push("provider = @provider"); values.provider = patch.provider; }
    if ("tier" in patch) { fields.push("tier = @tier"); values.tier = patch.tier ?? tierForProvider(patch.provider ?? existing.provider); }
    if ("max_tokens" in patch) { fields.push("max_tokens = @max_tokens"); values.max_tokens = patch.max_tokens ?? null; }
    if (patch.active !== undefined) { fields.push("active = @active"); values.active = patch.active ? 1 : 0; }
    if ("notes" in patch) { fields.push("notes = @notes"); values.notes = patch.notes ?? null; }
    if ("cost_per_m_input" in patch) { fields.push("cost_per_m_input = @cost_per_m_input"); values.cost_per_m_input = patch.cost_per_m_input ?? null; }
    if ("cost_per_m_output" in patch) { fields.push("cost_per_m_output = @cost_per_m_output"); values.cost_per_m_output = patch.cost_per_m_output ?? null; }
    if ("thinking_mode" in patch) { fields.push("thinking_mode = @thinking_mode"); values.thinking_mode = patch.thinking_mode ?? "default"; }

    if (fields.length === 0) return existing;
    this.db.prepare("UPDATE models SET " + fields.join(", ") + " WHERE id = @id").run(values);
    return this.get(id);
  }

  delete(id: string): boolean {
    this.db.prepare("DELETE FROM role_assignments WHERE model_id = ?").run(id);
    const result = this.db.prepare("DELETE FROM models WHERE id = ?").run(id);
    return result.changes > 0;
  }

  getRoles(): Record<ModelRole, ModelEntry | null> {
    const entries = this.list();
    const result = {} as Record<ModelRole, ModelEntry | null>;
    for (const role of ALL_MODEL_ROLES) {
      result[role] = entries.find((entry) => entry.active && entry.roles.includes(role)) ?? null;
    }
    return result;
  }

  assignRole(role: ModelRole, modelId: string | null): void {
    if (modelId) {
      this.db.prepare("INSERT OR REPLACE INTO role_assignments (role, model_id) VALUES (?, ?)").run(role, modelId);
    } else {
      this.db.prepare("DELETE FROM role_assignments WHERE role = ?").run(role);
    }
  }

  getHealth(): ModelRegistryHealth {
    const entries = this.list();
    const roles = this.getRoles();
    const activeCloudModels = entries.filter((entry) => !entry.provider.includes("provider-ollama") && !entry.provider.includes("provider-llamacpp"));
    const missingCoreRoles = CORE_ROLE_REQUIREMENTS.filter((role) => !roles[role]);

    let trust: RegistryTrust = "trusted";
    let hint = this.healthHint;

    if (this.healthHint?.toLowerCase().includes("corrupt")) {
      trust = "degraded";
    } else if (this.bootstrapSource === "lite-defaults") {
      trust = "verified";
      hint = hint ?? "Lite defaults loaded.";
    } else if (missingCoreRoles.length > 0) {
      trust = "verified";
      hint = hint ?? ("Unassigned roles: " + missingCoreRoles.join(", "));
    }

    return {
      trust,
      mode: !this.cloudEnabled && activeCloudModels.length === 0 ? "lite" : "full",
      dbPath: this.dbPath,
      contract: NOUS_CONTRACT,
      hint,
      cloudEnabled: this.cloudEnabled,
      bootstrapSource: this.bootstrapSource,
    };
  }

  close(): void {
    this.db.close();
  }
}

let _registry: ModelRegistry | null = null;

export function getModelRegistry(baseDir?: string): ModelRegistry {
  if (!_registry) {
    const base = baseDir ?? process.env["SQUIDLEY_BASE_DIR"] ?? process.cwd();
    _registry = new ModelRegistry(base);
  }
  return _registry;
}
